INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00620', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於要約之敘述，何者錯誤？', '["非對話為要約者，依通常情形可期待承諾之達到時期內，相對人不為承諾時，失其拘束力", "對話為要約者，非立時承諾，即失其拘束力", "要約定有承諾期限者，非於其期限內為承諾，失其拘束力", "將要約擴張、限制或為其他變更而承諾者，視為承諾"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00621', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲至乙運動用品店購買名牌球鞋一雙，價格為新臺幣（下同）6000元，惟該店只有白色款式，甲 要買紅色款式，乙表示要調貨，要求甲交付定金1000元，甲遂交付定金給乙。下列敘述，何者正確？', '["定金契約為諾成契約", "因甲後來在另一家店買到紅色球鞋，甲得撤銷該契約，將定金1000元取回", "因甲僅交付1000元，非球鞋之全部價金，故推定該球鞋的買賣契約尚不成立", "因乙訂貨的過失，致使全臺最後一雙該款紅色球鞋被賣出，致使乙無法交貨給甲，所以必須加 倍返還給甲2000元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00622', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲對乙有新臺幣（下同）20萬元債權，將其出賣並讓與給第三人丙。下列敘述，何者正確？', '["甲對乙之債權，屬於性質上不得讓與之債權", "甲將債權讓與給丙，若未通知乙，該債權讓與無效", "甲將債權出賣給丙，若未得乙之同意，則屬效力未定", "透過甲丙之讓與合意，甲對乙之債權即移轉給丙，由丙取得對乙之20萬元債權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00623', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲向乙借一幅畫，然後以「易占有為所有」之意思，對外（包括乙在內）公然表示自己是該畫之 所有人，繼續10年占有該畫，乙未表示異議。下列敘述，何者正確？', '["乙得請求甲返還不當得利", "乙得向甲請求返還所有物", "甲時效取得該畫之所有權", "甲繼受取得該畫之所有權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00624', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲乙丙三人分別共有A地，三人就A地於民國100年訂立分管契約後，甲將其應有部分讓與丁。 下列敘述，何者正確？', '["分管契約是債權行為，應先辦理登記，始對受讓在後之丁有拘束力", "分管契約是物權行為，無須辦理登記，對受讓人丁仍繼續有拘束力", "分管契約是債權行為，無須辦理登記，對受讓人丁仍繼續有拘束力", "分管契約是物權行為，應先辦理登記，始對受讓在後之丁有拘束力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00625', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲向乙貸款新臺幣100萬元，以甲所有之A 地為乙設定普通抵押權，嗣後甲將A地出賣予丙並 完成所有權移轉登記。債務清償期屆至，甲無力清償債務。下列敘述，何者錯誤？', '["乙得以丙為相對人，聲請法院裁定准許拍賣A地", "乙應以丙為被告，向法院起訴請求丙清償甲債務", "丙之債權人聲請拍賣A地，乙有優先受清償之權", "甲將A地出賣予丙並完成所有權移轉登記，乙不得反對"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00626', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '乙偷甲之A腳踏車，嗣後A腳踏車又遭丙竊取，乙當場隨即發現丙之行為。乙對丙不得主張下列 何種權利？', '["占有防禦權", "占有物取回權", "占有物返還請求權", "所有物返還請求權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00627', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下種何者，縱使尚未完成不動產物權變動之登記，權利人亦已於登記前即取得該不動產物權？', '["典權人因出典人於典期屆滿後，經過2年不以原典價回贖，而取得典物所有權者", "法院命被告履行不動產物權移轉登記之給付判決確定時", "占有人以所有之意思，20年間和平、公然、繼續占有他人未登記之不動產而主張時效取得所有 權者", "共有人全體對於共有不動產之分割協議完成時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00628', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列關於區分地上權排他效力之敘述，何者正確？', '["土地所有人於同一土地設定區分地上權後，應得該區分地上權人同意，始得再設定用益物權或 另一區分地上權", "土地所有人於同一土地設定區分地上權後，即不許其再設定用益物權或另一區分地上權", "土地所有人於同一土地設定區分地上權後，毋庸該區分地上權人同意，亦得再設定用益物權或 另一區分地上權", "土地所有人於同一土地設定區分地上權後，即不許其再設定用益物權，僅得於未重疊之空間範 圍設定另一區分地上權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00629', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-110-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '關於婚姻之要件及其效力，下列敘述，何者正確？', '["結婚應以書面為之，並有2人以上證人之簽名與公開之儀式後，攜公開儀式之影音照片，至法 院公證處為登記，該婚姻始生效力", "有配偶者重婚時，前婚姻應經後婚之當事人請求法院裁定為無效", "未成年人結婚，未得法定代理人同意時，其法定代理人應於知悉後2年內，向法院請求撤銷之。 但未成年人已分居者，不在此限", "結婚撤銷之效力，不溯及既往"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:57+00:00", "source_pdf_sha1": "17a8c663fd9d", "answer_pdf_sha1": "7e5cdb5cd90a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "404", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
